#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define Ls(x) (x<<1)
#define Rs(x) (x<<1|1)
#define N 500005
using namespace std;
inline void debug();
struct Seg{int l,r,sum,lmx,rmx,nmx;}t[N<<2|1];
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9'){if(ch=='-')flag=1;ch=getchar();}
	while(ch<='9'&&ch>='0')res=(res<<1)+(res<<3)+(ch^48),ch=getchar();
	return flag?-res:res;
}
int a[N],n,m;
inline Seg Max(int l,int r,int cur)
{
	if(l<=t[cur].l&&t[cur].r<=r)return t[cur];
	int mid=(t[cur].l+t[cur].r)>>1;
	if(r<=mid)return Max(l,r,Ls(cur));
	if(l>mid)return Max(l,r,Rs(cur));
	Seg ls=Max(l,r,Ls(cur)),rs=Max(l,r,Rs(cur)),k;
	k.lmx=max(ls.lmx,ls.sum+rs.lmx);
	k.rmx=max(rs.rmx,rs.sum+ls.rmx);
	k.nmx=max(max(ls.nmx,rs.nmx),ls.rmx+rs.lmx);
	k.sum=ls.sum+rs.sum;return k;
}
inline void update(int k)
{
	t[k].sum=t[Ls(k)].sum+t[Rs(k)].sum;
	t[k].lmx=max(t[Ls(k)].lmx,t[Ls(k)].sum+t[Rs(k)].lmx);
	t[k].rmx=max(t[Rs(k)].rmx,t[Rs(k)].sum+t[Ls(k)].rmx);
	t[k].nmx=max(max(t[Ls(k)].nmx,t[Rs(k)].nmx),t[Ls(k)].rmx+t[Rs(k)].lmx);
}
inline void build(int l,int r,int cur)
{
	t[cur].l=l;t[cur].r=r;
	if(l==r){t[cur].sum=t[cur].rmx=t[cur].nmx=t[cur].lmx=a[l];return;}
	int mid=(l+r)>>1;build(l,mid,Ls(cur));build(mid+1,r,Rs(cur));
	update(cur);return;
}
inline void Fix(int p,int val,int cur)
{
	if(t[cur].l==t[cur].r){t[cur].sum=t[cur].rmx=t[cur].nmx=t[cur].lmx=val;return;}
	int mid=(t[cur].l+t[cur].r)>>1;
	if(p<=mid) Fix(p,val,Ls(cur)); else Fix(p,val,Rs(cur));
	update(cur);return;
}
inline void debug()
{
	rep(1,n<<1,i)
	{
		printf("%d %d : %d %d %d %d\n",t[i].l,t[i].r,t[i].lmx,t[i].rmx,t[i].nmx,t[i].sum);
	}
	puts("");
}
int main()
{
	n=read();rep(1,n,i)a[i]=read();build(1,n,1);
	m=read();rep(1,m,i)
	{
		int opt=read(),x,y;
		if(opt==0)x=read(),y=read(),Fix(x,y,1);
		else 
		{
			x=read(),y=read();if(y<x)swap(x,y);
			printf("%d\n",Max(x,y,1).nmx);
		}
		
	}
	return 0;
}
